#!/usr/bin/env node
// Diagnostic test for the cross-project source-generator scenario.
// Drives `textDocument/definition` on `IGreeter` and `GreetResponse`
// from `examples/multi-project/Consumer/Greeting.cs`. Both types are
// generated by `Generator` and live in the in-memory compilation of
// `Producer`, which `Consumer` references via ProjectReference.
//
// The point is NOT to assert a specific outcome — it's to capture
// exactly what the Roslyn LSP returns so we can decide whether the
// failure (no go-to-def in this scenario) is in the shim, in Roslyn's
// response, or somewhere else.
//
// Security note: this test uses spawn() and spawnSync() with explicit
// argv arrays. shell: false. No external/user input flows into the
// command lines — paths come from __dirname only.

'use strict';

const cp = require('node:child_process');
const fs = require('node:fs');
const path = require('node:path');
const os = require('node:os');

const PROJECT_ROOT = path.resolve(__dirname, '..', 'examples', 'multi-project');
const SOURCE_FILE = path.join(PROJECT_ROOT, 'Consumer', 'Greeting.cs');
const PRODUCER_CSPROJ = path.join(PROJECT_ROOT, 'Producer', 'Producer.csproj');
const CONSUMER_CSPROJ = path.join(PROJECT_ROOT, 'Consumer', 'Consumer.csproj');
const SHIM = path.resolve(__dirname, '..', 'src', 'shim.js');

const PROBES = [
  { label: 'IGreeter (cross-project generated interface)', token: 'IGreeter', context: ': IGreeter' },
  { label: 'GreetResponse (cross-project generated record)', token: 'GreetResponse', context: 'GreetResponse Greet' },
];

function pathToFileUri(p) {
  return 'file://' + path.resolve(p);
}

function frame(message) {
  const body = Buffer.from(JSON.stringify(message), 'utf8');
  return Buffer.concat([
    Buffer.from(`Content-Length: ${body.length}\r\n\r\n`, 'ascii'),
    body,
  ]);
}

class Reader {
  constructor() {
    this.buf = Buffer.alloc(0);
    this.messages = [];
    this.listeners = [];
  }
  push(chunk) {
    this.buf = Buffer.concat([this.buf, chunk]);
    while (true) {
      const headerEnd = this.buf.indexOf('\r\n\r\n');
      if (headerEnd < 0) return;
      const header = this.buf.slice(0, headerEnd).toString('ascii');
      const m = /Content-Length:\s*(\d+)/i.exec(header);
      if (!m) { this.buf = this.buf.slice(headerEnd + 4); continue; }
      const len = parseInt(m[1], 10);
      if (this.buf.length < headerEnd + 4 + len) return;
      const body = this.buf.slice(headerEnd + 4, headerEnd + 4 + len).toString('utf8');
      this.buf = this.buf.slice(headerEnd + 4 + len);
      let msg;
      try { msg = JSON.parse(body); } catch (_) { continue; }
      this.messages.push(msg);
      for (let i = this.listeners.length - 1; i >= 0; i--) {
        const L = this.listeners[i];
        if (L.predicate(msg)) {
          clearTimeout(L.timer);
          this.listeners.splice(i, 1);
          L.resolve(msg);
        }
      }
    }
  }
  wait(predicate, timeoutMs = 30_000, label = 'predicate') {
    const existing = this.messages.find(predicate);
    if (existing) return Promise.resolve(existing);
    return new Promise((resolve, reject) => {
      const L = { predicate, resolve };
      L.timer = setTimeout(() => {
        const idx = this.listeners.indexOf(L);
        if (idx >= 0) this.listeners.splice(idx, 1);
        reject(new Error(`timeout waiting for ${label}`));
      }, timeoutMs);
      this.listeners.push(L);
    });
  }
  waitForId(id, timeoutMs) { return this.wait((m) => m.id === id, timeoutMs, `id=${id}`); }
  waitForMethod(method, timeoutMs) { return this.wait((m) => m.method === method, timeoutMs, `method=${method}`); }
}

function findProbePosition(source, probe) {
  const lines = source.split('\n');
  for (let i = 0; i < lines.length; i++) {
    const idx = lines[i].indexOf(probe.context);
    if (idx >= 0) {
      const tokenIdx = lines[i].indexOf(probe.token, idx);
      if (tokenIdx >= 0) {
        return { line: i, character: tokenIdx + Math.floor(probe.token.length / 2) };
      }
    }
  }
  return null;
}

function summarizeLocation(loc) {
  if (!loc) return '<null>';
  if (loc.uri) return `Location { uri=${loc.uri} }`;
  if (loc.targetUri) return `LocationLink { targetUri=${loc.targetUri} }`;
  return `<unknown shape: ${JSON.stringify(loc)}>`;
}

async function run() {
  console.log('--- restoring + building multi-project graph ---');
  const buildResult = cp.spawnSync('dotnet', ['build', CONSUMER_CSPROJ, '--nologo', '-v', 'minimal'], {
    cwd: PROJECT_ROOT,
    stdio: 'inherit',
    shell: false,
  });
  if (buildResult.status !== 0) {
    throw new Error(`dotnet build failed with status ${buildResult.status}`);
  }

  console.log('\n--- spawning shim with shim log enabled ---');
  const logPath = path.join(os.tmpdir(), `shim-diag-${process.pid}.log`);
  try { fs.unlinkSync(logPath); } catch (_) {}
  const env = Object.assign({}, process.env, { ROSLYN_SHIM_LOG: logPath });

  const extraArgs = process.env.SHIM_EXTRA_ARGS
    ? process.env.SHIM_EXTRA_ARGS.split(/\s+/).filter(Boolean)
    : [];
  const shim = cp.spawn('node', [SHIM, '--stdio', '--logLevel', 'Warning', ...extraArgs], {
    stdio: ['pipe', 'pipe', 'inherit'],
    shell: false,
    env,
  });

  const reader = new Reader();
  shim.stdout.on('data', (c) => reader.push(c));
  function send(msg) { shim.stdin.write(frame(msg)); }

  console.log('--- initialize ---');
  const projectRootUri = pathToFileUri(PROJECT_ROOT);
  send({
    jsonrpc: '2.0', id: 1, method: 'initialize',
    params: {
      processId: process.pid,
      rootUri: projectRootUri,
      workspaceFolders: [{ uri: projectRootUri, name: 'multi-project' }],
      capabilities: {
        textDocument: {
          synchronization: { dynamicRegistration: false },
          definition: { linkSupport: true },
          implementation: { linkSupport: true },
        },
      },
    },
  });
  await reader.waitForId(1, 30_000);
  send({ jsonrpc: '2.0', method: 'initialized', params: {} });

  // Hypothesis: OpenCode only opens the project containing the file
  // under cursor, NOT all projects in the workspace. Open only Consumer
  // to mimic that behaviour and see whether go-to-def into Producer's
  // generated types still works.
  const SKIP_PROJECT_OPEN = process.env.SKIP_PROJECT_OPEN === '1';
  const OPEN_ONLY_CONSUMER = process.env.OPEN_ONLY_CONSUMER === '1';
  if (SKIP_PROJECT_OPEN) {
    console.log('--- skipping project/open entirely (relying on auto-discovery) ---');
  } else if (OPEN_ONLY_CONSUMER) {
    console.log('--- opening Consumer ONLY (Producer omitted on purpose) ---');
    send({
      jsonrpc: '2.0', method: 'project/open',
      params: { projects: [pathToFileUri(CONSUMER_CSPROJ)] },
    });
  } else {
    console.log('--- opening Producer + Consumer projects ---');
    send({
      jsonrpc: '2.0', method: 'project/open',
      params: {
        projects: [pathToFileUri(PRODUCER_CSPROJ), pathToFileUri(CONSUMER_CSPROJ)],
      },
    });
  }

  console.log('--- waiting for project initialization ---');
  const source = fs.readFileSync(SOURCE_FILE, 'utf8');
  const sourceUri = pathToFileUri(SOURCE_FILE);
  send({
    jsonrpc: '2.0', method: 'textDocument/didOpen',
    params: {
      textDocument: {
        uri: sourceUri,
        languageId: 'csharp',
        version: 1,
        text: source,
      },
    },
  });
  await reader.waitForMethod('workspace/projectInitializationComplete', 180_000);
  console.log('    ✓ project initialization complete\n');

  let nextRequestId = 100;
  for (const probe of PROBES) {
    const pos = findProbePosition(source, probe);
    if (!pos) {
      console.log(`!! could not find probe ${probe.label} in source — skipping`);
      continue;
    }
    console.log(`>>> probe: ${probe.label}`);
    console.log(`    cursor: line=${pos.line} character=${pos.character}`);

    const defId = nextRequestId++;
    send({
      jsonrpc: '2.0', id: defId, method: 'textDocument/definition',
      params: { textDocument: { uri: sourceUri }, position: pos },
    });
    const defResp = await reader.waitForId(defId, 30_000);
    if (defResp.error) {
      console.log(`    ✗ /definition errored: ${JSON.stringify(defResp.error)}`);
    } else {
      const result = defResp.result;
      console.log(`    /definition raw result: ${JSON.stringify(result)}`);
      if (result === null || (Array.isArray(result) && result.length === 0)) {
        console.log(`    ✗ EMPTY — Roslyn returned no location for this symbol.`);
        console.log(`      The shim never sees a virtual URI to translate.`);
      } else {
        const arr = Array.isArray(result) ? result : [result];
        for (const loc of arr) console.log(`    location: ${summarizeLocation(loc)}`);
      }
    }

    const implId = nextRequestId++;
    send({
      jsonrpc: '2.0', id: implId, method: 'textDocument/implementation',
      params: { textDocument: { uri: sourceUri }, position: pos },
    });
    const implResp = await reader.waitForId(implId, 30_000);
    if (implResp.error) {
      console.log(`    ✗ /implementation errored: ${JSON.stringify(implResp.error)}`);
    } else {
      console.log(`    /implementation raw result: ${JSON.stringify(implResp.result)}`);
    }

    const refId = nextRequestId++;
    send({
      jsonrpc: '2.0', id: refId, method: 'textDocument/references',
      params: {
        textDocument: { uri: sourceUri },
        position: pos,
        context: { includeDeclaration: true },
      },
    });
    const refResp = await reader.waitForId(refId, 30_000);
    if (refResp.error) {
      console.log(`    ✗ /references errored: ${JSON.stringify(refResp.error)}`);
    } else {
      const result = refResp.result;
      const arr = Array.isArray(result) ? result : (result ? [result] : []);
      console.log(`    /references returned ${arr.length} location(s)`);
      for (const loc of arr) console.log(`        ${summarizeLocation(loc)}`);
    }
    console.log('');
  }

  console.log('--- shutting down ---');
  send({ jsonrpc: '2.0', id: 9999, method: 'shutdown' });
  await reader.waitForId(9999, 10_000).catch(() => {});
  send({ jsonrpc: '2.0', method: 'exit' });
  await Promise.race([
    new Promise((r) => shim.on('exit', r)),
    new Promise((r) => setTimeout(() => { try { shim.kill('SIGKILL'); } catch (_) {} r(); }, 5000)),
  ]);

  console.log('\n--- shim log ---');
  try {
    const log = fs.readFileSync(logPath, 'utf8');
    console.log(log);
  } catch (_) {
    console.log('(no log file written)');
  }
}

run().then(() => process.exit(0), (err) => {
  console.error('FAIL', err.message);
  console.error(err.stack);
  process.exit(1);
});
